/**
 * Morning-After Report — AST-31
 *
 * Shows a summary overlay when the player returns after being away.
 * Displays resources gathered, research progress, robot activity, and ARIA commentary.
 * Dismissed by clicking "Resume Operations."
 */

import type { OfflineResult } from '../sim/offlineSim';
import { safeHtml } from './utils/safeHtml';

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Show the morning-after report overlay.
 * @param result Offline simulation result
 * @param onDismiss Callback when player dismisses the report
 */
export function showMorningReport(result: OfflineResult, onDismiss: () => void): void {
  const overlay = buildOverlay(result, onDismiss);
  document.body.appendChild(overlay);
}

// ── Building the overlay ──────────────────────────────────────────────────────

function fmt(n: number): string {
  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
  return Math.round(n).toString();
}

function buildAriaCommentary(result: OfflineResult): string {
  const { robotCounts, elapsedLabel, researchGained, anomaliesFound } = result;
  const totalRobots = Object.values(robotCounts).reduce((s, n) => s + n, 0);

  if (totalRobots === 0) {
    return `[ARIA] Fleet status: dormant. No robots were active during your absence of ${elapsedLabel}. Operations are ready to resume on your command.`;
  }

  const parts: string[] = [];
  parts.push(`[ARIA] Overnight report — you were away for ${elapsedLabel}.`);

  if (robotCounts.miners > 0) {
    const totalOre = Object.values(result.resourcesGained).reduce((s, n) => s + n, 0);
    parts.push(
      `${robotCounts.miners} Miner${robotCounts.miners > 1 ? 's' : ''} continued extraction operations, adding approximately ${fmt(totalOre)} units of raw ore to storage.`,
    );
  }

  if (robotCounts.researchers > 0 && researchGained > 0) {
    parts.push(
      `Research teams accumulated ${fmt(researchGained)} research points — check the tech tree for any newly affordable nodes.`,
    );
  }

  if (anomaliesFound > 0) {
    parts.push(
      `Scout sweep patterns flagged ${anomaliesFound} potential anomal${anomaliesFound > 1 ? 'ies' : 'y'} worth investigating.`,
    );
  }

  if (result.wasCapped) {
    parts.push(
      `Note: simulation was capped at 8 hours. Additional elapsed time was not simulated.`,
    );
  }

  parts.push(`All systems nominal. Ready when you are, operator.`);
  return parts.join(' ');
}

function buildOverlay(result: OfflineResult, onDismiss: () => void): HTMLDivElement {
  const overlay = document.createElement('div');
  overlay.id = 'morning-report-overlay';
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.92);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 500;
    backdrop-filter: blur(6px);
  `;

  const card = document.createElement('div');
  card.style.cssText = `
    width: 560px;
    max-height: 80vh;
    overflow-y: auto;
    background: #080e1a;
    border: 1px solid #1e3a5f;
    border-radius: 10px;
    padding: 28px;
    color: #c8d8e8;
    font-family: 'Courier New', monospace;
    font-size: 13px;
  `;

  // ── Header
  card.innerHTML = safeHtml`
    <div style="margin-bottom:20px">
      <div style="font-size:20px;font-weight:bold;color:#e2e8f0;margin-bottom:4px">
        ◈ OVERNIGHT REPORT
      </div>
      <div style="color:#64748b;font-size:11px">
        You were away for <span style="color:#94a3b8">${result.elapsedLabel}</span>
        ${result.wasCapped ? ' <span style="color:#f59e0b">(capped at 8h)</span>' : ''}
        · ${fmt(result.ticksSimulated)} sim ticks estimated
      </div>
    </div>
  `;

  // ── Fleet status
  const { robotCounts } = result;
  const totalRobots = Object.values(robotCounts).reduce((s, n) => s + n, 0);

  if (totalRobots > 0) {
    const fleetSection = document.createElement('div');
    fleetSection.style.cssText = 'margin-bottom:16px';
    fleetSection.innerHTML = safeHtml`
      <div style="color:#60a5fa;font-size:11px;font-weight:bold;margin-bottom:8px;text-transform:uppercase;letter-spacing:1px">Fleet Activity</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
        ${robotCounts.miners > 0 ? robotRow('Miners', robotCounts.miners, 'active, ore extraction') : ''}
        ${robotCounts.scouts > 0 ? robotRow('Scouts', robotCounts.scouts, 'active, sweep patterns') : ''}
        ${robotCounts.haulers > 0 ? robotRow('Haulers', robotCounts.haulers, 'active, logistics') : ''}
        ${robotCounts.researchers > 0 ? robotRow('Researchers', robotCounts.researchers, 'active, research') : ''}
        ${robotCounts.refiners > 0 ? robotRow('Refiners', robotCounts.refiners, 'active, processing') : ''}
      </div>
    `;
    card.appendChild(fleetSection);
  }

  // ── Resources gained
  const hasResources = Object.values(result.resourcesGained).some((v) => v > 0.5);
  if (hasResources) {
    const resSection = document.createElement('div');
    resSection.style.cssText = 'margin-bottom:16px';
    resSection.innerHTML = `<div style="color:#22c55e;font-size:11px;font-weight:bold;margin-bottom:8px;text-transform:uppercase;letter-spacing:1px">Resources Gathered</div>`;

    const grid = document.createElement('div');
    grid.style.cssText = 'display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px';

    for (const [resource, amount] of Object.entries(result.resourcesGained)) {
      if (amount < 0.5) continue;
      const item = document.createElement('div');
      item.style.cssText =
        'background:rgba(20,30,50,0.8);border:1px solid #1f2937;border-radius:4px;padding:6px 8px';
      item.innerHTML = safeHtml`
        <div style="color:#94a3b8;font-size:10px;text-transform:capitalize">${resource}</div>
        <div style="color:#4ade80;font-weight:bold">+${fmt(amount)}</div>
      `;
      grid.appendChild(item);
    }
    resSection.appendChild(grid);

    if (Object.values(result.refinedGained).some((v) => v > 0)) {
      const refinedNote = document.createElement('div');
      refinedNote.style.cssText = 'margin-top:8px;color:#a78bfa;font-size:11px';
      const refinedStr = Object.entries(result.refinedGained)
        .filter(([, v]) => v > 0.5)
        .map(([k, v]) => `${fmt(v)} ${k.replace(/_/g, ' ')}`)
        .join(', ');
      if (refinedStr) refinedNote.textContent = `Refinery output: ${refinedStr}`;
      resSection.appendChild(refinedNote);
    }

    card.appendChild(resSection);
  }

  // ── Research
  if (result.researchGained > 1) {
    const researchSection = document.createElement('div');
    researchSection.style.cssText = 'margin-bottom:16px';
    researchSection.innerHTML = safeHtml`
      <div style="color:#f59e0b;font-size:11px;font-weight:bold;margin-bottom:8px;text-transform:uppercase;letter-spacing:1px">Research</div>
      <div style="background:rgba(20,30,50,0.8);border:1px solid #1f2937;border-radius:4px;padding:8px">
        <span style="color:#fbbf24">+${fmt(result.researchGained)}</span>
        <span style="color:#64748b"> research points accumulated — check the tech tree</span>
      </div>
    `;
    card.appendChild(researchSection);
  }

  // ── Anomalies
  if (result.anomaliesFound > 0) {
    const anomSection = document.createElement('div');
    anomSection.style.cssText = 'margin-bottom:16px';
    anomSection.innerHTML = safeHtml`
      <div style="color:#a855f7;font-size:11px;font-weight:bold;margin-bottom:8px;text-transform:uppercase;letter-spacing:1px">Anomaly Sweep</div>
      <div style="background:rgba(20,10,40,0.8);border:1px solid #3b1f6e;border-radius:4px;padding:8px;color:#c084fc">
        Scouts flagged ${result.anomaliesFound} potential anomal${result.anomaliesFound > 1 ? 'ies' : 'y'}.
        Deploy scout units to investigate.
      </div>
    `;
    card.appendChild(anomSection);
  }

  // ── ARIA commentary
  const aria = document.createElement('div');
  aria.style.cssText = `
    margin-bottom: 24px;
    padding: 12px;
    background: rgba(100, 0, 150, 0.08);
    border: 1px solid #4c1d95;
    border-radius: 6px;
    color: #c084fc;
    font-size: 12px;
    line-height: 1.5;
  `;
  aria.textContent = buildAriaCommentary(result);
  card.appendChild(aria);

  // ── Resume button
  const btn = document.createElement('button');
  btn.textContent = '▶ Resume Operations';
  btn.style.cssText = `
    width: 100%;
    padding: 12px;
    background: #1d4ed8;
    color: #e2e8f0;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: bold;
    cursor: pointer;
    font-family: inherit;
    letter-spacing: 0.5px;
  `;
  btn.onmouseover = () => (btn.style.background = '#2563eb');
  btn.onmouseout = () => (btn.style.background = '#1d4ed8');
  btn.onclick = () => {
    overlay.remove();
    onDismiss();
  };
  card.appendChild(btn);

  overlay.appendChild(card);
  return overlay;
}

function robotRow(label: string, count: number, status: string): string {
  return `
    <div style="background:rgba(20,30,50,0.8);border:1px solid #1f2937;border-radius:4px;padding:6px 8px">
      <div style="color:#94a3b8;font-size:10px">${label}</div>
      <div><span style="color:#60a5fa;font-weight:bold">${count}</span>
        <span style="color:#374151;font-size:10px"> ${status}</span>
      </div>
    </div>
  `;
}
